import torch
import torch.nn as nn
import torchvision.models as models

class VOC2012Model(nn.Module):
    def __init__(self, num_classes=20, num_anchors=3):
        super(VOC2012Model, self).__init__()
        self.num_classes = num_classes
        self.num_anchors = num_anchors
        
        resnet = models.resnet50(weights=models.ResNet50_Weights.DEFAULT)
        
        self.backbone = nn.Sequential(*list(resnet.children())[:-2])
        
        self.detection_head = nn.Sequential(
            nn.Conv2d(2048, 1024, kernel_size=3, padding=1),
            nn.BatchNorm2d(1024),
            nn.LeakyReLU(0.1),
            nn.Conv2d(1024, num_anchors * (5 + num_classes), kernel_size=1)
        )

    def forward(self, x):
        features = self.backbone(x) 
        out = self.detection_head(features) 
        
        batch_size, _, grid_h, grid_w = out.shape
        out = out.view(batch_size, self.num_anchors, 5 + self.num_classes, grid_h, grid_w)
        out = out.permute(0, 3, 4, 1, 2).contiguous()
        
        pred_boxes = out[..., :4]        
        pred_conf = out[..., 4:5]        
        pred_classes = out[..., 5:]    
        
        return {
            "pred_boxes": pred_boxes,
            "pred_conf": pred_conf,
            "pred_classes": pred_classes
        }

if __name__ == "__main__":
    dummy_images = torch.randn(2, 3, 224, 224)
    model = VOC2012Model(num_classes=20, num_anchors = 5)
    outputs = model(dummy_images)
    print("--- KIỂM TRA MẠNG RESNET THÀNH CÔNG ---")
    print("Kích thước đầu ra hộp thoại:", outputs["pred_boxes"].shape)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
    print("Kích thước đầu ra nhãn lớp:", outputs["pred_classes"].shape) 